/**
 * Skill Discovery Engine
 *
 * Maps a user's interests and natural aptitudes against structured skill
 * progressions to surface three types of recommendations:
 *
 *   1. Strong Matches  — high interest + high aptitude alignment
 *   2. Hidden Potential — high aptitude but low/no interest signal (the key insight)
 *   3. Growth Edges    — high interest but current aptitude gap
 *
 * The engine uses 11 trait dimensions scored from 8 questions. Each skill tree
 * has a hand-tuned trait profile. Recommendations are generated by computing
 * the dot product of the user's trait vector against each tree's profile,
 * split by interest vs. aptitude dimensions.
 *
 * This is not a personality test. It is a structured starting point for
 * exploration, grounded in the same dimensions that underlie the skill maps.
 */

// ---------------------------------------------------------------------------
// Traits
// ---------------------------------------------------------------------------

export type Trait =
  | "physical"
  | "creative"
  | "analytical"
  | "social"
  | "strategic"
  | "patience"
  | "competitive"
  | "expressive"
  | "technical"
  | "wellness"
  | "naturalistic";

export type TraitScores = Partial<Record<Trait, number>>;

// ---------------------------------------------------------------------------
// Questions
// ---------------------------------------------------------------------------

export interface DiscoverOption {
  id: string;
  label: string;
  /** Trait weights when this option signals interest. */
  interest: TraitScores;
  /** Trait weights when this option signals aptitude. */
  aptitude: TraitScores;
}

export interface DiscoverQuestion {
  id: string;
  title: string;
  subtitle?: string;
  type: "single" | "multi";
  maxSelections?: number;
  options: DiscoverOption[];
}

