// ---------------------------------------------------------------------------
// Scoring & Recommendations
// ---------------------------------------------------------------------------

export type RecommendationCategory =
  | "strong-match"
  | "hidden-potential"
  | "growth-edge";

export interface SkillRecommendation {
  tree: TreeProfile;
  category: RecommendationCategory;
  interestScore: number;
  aptitudeScore: number;
  totalScore: number;
  reasoning: string;
}

/** User's accumulated answers: questionId → array of selected option IDs. */
export type DiscoverAnswers = Record<string, string[]>;

interface TraitProfile {
  interest: TraitScores;
  aptitude: TraitScores;
}

function addTraits(target: TraitScores, source: TraitScores): void {
  for (const [trait, value] of Object.entries(source)) {
    const t = trait as Trait;
    target[t] = (target[t] ?? 0) + (value ?? 0);
  }
}

function dotProduct(userTraits: TraitScores, treeTraits: TraitScores): number {
  let sum = 0;
  for (const [trait, treeWeight] of Object.entries(treeTraits)) {
    const userWeight = userTraits[trait as Trait] ?? 0;
    sum += userWeight * (treeWeight ?? 0);
  }
  return sum;
}

function normalizeScores(scores: number[]): number[] {
  const max = Math.max(...scores, 1);
  return scores.map((s) => s / max);
}

/** Build a trait profile from the user's answers. */
export function buildTraitProfile(answers: DiscoverAnswers): TraitProfile {
  const interest: TraitScores = {};
  const aptitude: TraitScores = {};

  for (const question of DISCOVER_QUESTIONS) {
    const selected = answers[question.id] ?? [];
    for (const optionId of selected) {
      const option = question.options.find((o) => o.id === optionId);
      if (!option) continue;
      addTraits(interest, option.interest);
      addTraits(aptitude, option.aptitude);
    }
  }

  return { interest, aptitude };
}

/**
 * Top 2 trait names for a given trait profile, used in reasoning.
 */
function topTraits(traits: TraitScores, count: number): Trait[] {
  return Object.entries(traits)
    .filter(([, v]) => (v ?? 0) > 0)
    .sort((a, b) => (b[1] ?? 0) - (a[1] ?? 0))
    .slice(0, count)
    .map(([t]) => t as Trait);
}

import { TRAIT_DIMENSION_LABELS } from "@/lib/design-tokens";

const TRAIT_LABELS = TRAIT_DIMENSION_LABELS as Record<Trait, string>;

function buildReasoning(
  tree: TreeProfile,
  category: RecommendationCategory,
  userProfile: TraitProfile,
): string {
  const treeTopTraits = topTraits(tree.traits, 2);
  const traitNames = treeTopTraits.map((t) => TRAIT_LABELS[t]).join(" and ");

  switch (category) {
    case "strong-match":
      return `Your interests align with ${tree.title}, and your natural ${traitNames} give you a strong foundation. ${tree.hook}`;
    case "hidden-potential": {
      const userAptTop = topTraits(userProfile.aptitude, 3);
      const overlap = treeTopTraits.filter((t) => userAptTop.includes(t));
      const overlapNames = overlap.length > 0
        ? overlap.map((t) => TRAIT_LABELS[t]).join(" and ")
        : traitNames;
      return `You may not have considered ${tree.title}, but your natural ${overlapNames} are exactly what it requires. ${tree.hook}`;
    }
    case "growth-edge":
      return `You're drawn to ${tree.title}, and while it will stretch your ${traitNames}, that's what makes it a powerful growth opportunity. ${tree.hook}`;
  }
}

/**
 * Generate skill recommendations from a user's answers.
 * Returns up to 8 recommendations across all three categories.
 */
export function generateRecommendations(
  answers: DiscoverAnswers,
): SkillRecommendation[] {
  const profile = buildTraitProfile(answers);

  // Score each tree
  const scored = TREE_PROFILES.map((tree) => {
    const interestRaw = dotProduct(profile.interest, tree.traits);
    const aptitudeRaw = dotProduct(profile.aptitude, tree.traits);
    return { tree, interestRaw, aptitudeRaw };
  });

  // Normalize separately
  const interestNorm = normalizeScores(scored.map((s) => s.interestRaw));
  const aptitudeNorm = normalizeScores(scored.map((s) => s.aptitudeRaw));

  const categorized = scored.map((s, i) => {
    const interestScore = interestNorm[i];
    const aptitudeScore = aptitudeNorm[i];
    const totalScore = interestScore + aptitudeScore;

    // Thresholds for categorization
    const highInterest = interestScore > 0.55;
    const highAptitude = aptitudeScore > 0.55;

    let category: RecommendationCategory;
    if (highInterest && highAptitude) {
      category = "strong-match";
    } else if (highAptitude && !highInterest) {
      category = "hidden-potential";
    } else if (highInterest && !highAptitude) {
      category = "growth-edge";
    } else {
      category = "growth-edge"; // low on both — still include if it scores well
    }

    return {
      tree: s.tree,
      category,
      interestScore,
      aptitudeScore,
      totalScore,
      reasoning: buildReasoning(s.tree, category, profile),
    };
  });

  // Sort by total score within each category
  const strongMatches = categorized
    .filter((r) => r.category === "strong-match")
    .sort((a, b) => b.totalScore - a.totalScore)
    .slice(0, 3);

  const hiddenPotential = categorized
    .filter((r) => r.category === "hidden-potential")
    .sort((a, b) => b.aptitudeScore - a.aptitudeScore)
    .slice(0, 3);

  const growthEdges = categorized
    .filter((r) => r.category === "growth-edge")
    .sort((a, b) => b.interestScore - a.interestScore)
    .slice(0, 2);

  return [...strongMatches, ...hiddenPotential, ...growthEdges];
}

/**
 * Generate recommendations using pre-computed trait vectors.
 * Used when a refined profile (with module signals) is available.
 */
export function generateRecommendationsFromProfile(
  interest: TraitScores,
  aptitude: TraitScores,
): SkillRecommendation[] {
  const profile: TraitProfile = { interest, aptitude };

  const scored = TREE_PROFILES.map((tree) => {
    const interestRaw = dotProduct(profile.interest, tree.traits);
    const aptitudeRaw = dotProduct(profile.aptitude, tree.traits);
    return { tree, interestRaw, aptitudeRaw };
  });

  const interestNorm = normalizeScores(scored.map((s) => s.interestRaw));
  const aptitudeNorm = normalizeScores(scored.map((s) => s.aptitudeRaw));

  const categorized = scored.map((s, i) => {
    const interestScore = interestNorm[i];
    const aptitudeScore = aptitudeNorm[i];
    const totalScore = interestScore + aptitudeScore;

    const highInterest = interestScore > 0.55;
    const highAptitude = aptitudeScore > 0.55;

    let category: RecommendationCategory;
    if (highInterest && highAptitude) {
      category = "strong-match";
    } else if (highAptitude && !highInterest) {
      category = "hidden-potential";
    } else if (highInterest && !highAptitude) {
      category = "growth-edge";
    } else {
      category = "growth-edge";
    }

    return {
      tree: s.tree,
      category,
      interestScore,
      aptitudeScore,
      totalScore,
      reasoning: buildReasoning(s.tree, category, profile),
    };
  });

  const strongMatches = categorized
    .filter((r) => r.category === "strong-match")
    .sort((a, b) => b.totalScore - a.totalScore)
    .slice(0, 3);

  const hiddenPotential = categorized
    .filter((r) => r.category === "hidden-potential")
    .sort((a, b) => b.aptitudeScore - a.aptitudeScore)
    .slice(0, 3);

  const growthEdges = categorized
    .filter((r) => r.category === "growth-edge")
    .sort((a, b) => b.interestScore - a.interestScore)
    .slice(0, 2);

  return [...strongMatches, ...hiddenPotential, ...growthEdges];
}

